/**
 * Web Worker entry point for OffscreenCanvas rendering.
 *
 * Receives an OffscreenCanvas via `transferControlToOffscreen()` and
 * executes serialized Canvas2D render commands off the main thread,
 * freeing the UI thread for interaction handling.
 *
 * Command binary layout (per command):
 *   byte 0: command type (u8)
 *   bytes 1+: type-specific payload (see RenderCommandType)
 *
 * Overall buffer layout:
 *   bytes 0-3: command count (Uint32, little-endian)
 *   bytes 4+: packed commands
 */

/** Discriminated command types stored in the binary stream. */
const enum RenderCommandType {
  /** moveTo(x, y) */
  MoveTo = 1,
  /** lineTo(x, y) */
  LineTo = 2,
  /** beginPath() */
  BeginPath = 3,
  /** stroke() */
  Stroke = 4,
  /** fill() */
  Fill = 5,
  /** fillRect(x, y, w, h) */
  FillRect = 6,
  /** strokeRect(x, y, w, h) */
  StrokeRect = 7,
  /** arc(x, y, r, startAngle, endAngle) */
  Arc = 8,
  /** closePath() */
  ClosePath = 9,
  /** setStrokeStyle — 4 bytes RGBA */
  SetStrokeStyle = 10,
  /** setFillStyle — 4 bytes RGBA */
  SetFillStyle = 11,
  /** setLineWidth(w) */
  SetLineWidth = 12,
  /** setTransform(a, b, c, d, e, f) */
  SetTransform = 13,
  /** clearRect(x, y, w, h) */
  ClearRect = 14,
  /** rect(x, y, w, h) */
  Rect = 15,
}

let canvas: OffscreenCanvas | null = null;
let ctx: OffscreenCanvasRenderingContext2D | null = null;

/** Messages from main thread -> worker. */
type WorkerInboundMessage =
  | { readonly type: 'init'; readonly canvas: OffscreenCanvas; readonly dpr: number }
  | { readonly type: 'render'; readonly data: ArrayBuffer; readonly width: number; readonly height: number; readonly dpr: number }
  | { readonly type: 'resize'; readonly width: number; readonly height: number; readonly dpr: number };

self.onmessage = (e: MessageEvent<WorkerInboundMessage>) => {
  const msg = e.data;

  switch (msg.type) {
    case 'init': {
      canvas = msg.canvas;
      const context = canvas.getContext('2d');
      if (context === null) {
        self.postMessage({ type: 'error', message: 'Failed to acquire 2D context on OffscreenCanvas' });
        return;
      }
      ctx = context;
      if (msg.dpr !== 1) {
        ctx.setTransform(msg.dpr, 0, 0, msg.dpr, 0, 0);
      }
      self.postMessage({ type: 'ready' });
      break;
    }

    case 'resize': {
      if (canvas) {
        canvas.width = Math.round(msg.width * msg.dpr);
        canvas.height = Math.round(msg.height * msg.dpr);
        if (ctx) {
          ctx.setTransform(msg.dpr, 0, 0, msg.dpr, 0, 0);
        }
      }
      break;
    }

    case 'render': {
      if (!ctx || !canvas) return;
      ctx.save();
      ctx.setTransform(1, 0, 0, 1, 0, 0);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.restore();

      executeCommandBuffer(ctx, msg.data);

      self.postMessage({ type: 'rendered' });
      break;
    }
  }
};

/**
 * Execute a packed binary command buffer against a Canvas2D context.
 *
 * Buffer format:
 *   [0..3]   Uint32  commandCount
 *   [4..]    packed commands, each starting with a Uint8 type tag
 */
function executeCommandBuffer(context: OffscreenCanvasRenderingContext2D, buffer: ArrayBuffer): void {
  if (buffer.byteLength < 4) return;

  const view = new DataView(buffer);
  const commandCount = view.getUint32(0, true);
  let offset = 4;

  for (let i = 0; i < commandCount; i++) {
    if (offset >= buffer.byteLength) break;

    const cmdType = view.getUint8(offset) as RenderCommandType;
    offset += 1;

    switch (cmdType) {
      case RenderCommandType.BeginPath:
        context.beginPath();
        break;

      case RenderCommandType.ClosePath:
        context.closePath();
        break;

      case RenderCommandType.Stroke:
        context.stroke();
        break;

      case RenderCommandType.Fill:
        context.fill();
        break;

      case RenderCommandType.MoveTo:
        context.moveTo(view.getFloat64(offset, true), view.getFloat64(offset + 8, true));
        offset += 16;
        break;

      case RenderCommandType.LineTo:
        context.lineTo(view.getFloat64(offset, true), view.getFloat64(offset + 8, true));
        offset += 16;
        break;

      case RenderCommandType.FillRect:
        context.fillRect(
          view.getFloat64(offset, true),
          view.getFloat64(offset + 8, true),
          view.getFloat64(offset + 16, true),
          view.getFloat64(offset + 24, true),
        );
        offset += 32;
        break;

      case RenderCommandType.StrokeRect:
        context.strokeRect(
          view.getFloat64(offset, true),
          view.getFloat64(offset + 8, true),
          view.getFloat64(offset + 16, true),
          view.getFloat64(offset + 24, true),
        );
        offset += 32;
        break;

      case RenderCommandType.ClearRect:
        context.clearRect(
          view.getFloat64(offset, true),
          view.getFloat64(offset + 8, true),
          view.getFloat64(offset + 16, true),
          view.getFloat64(offset + 24, true),
        );
        offset += 32;
        break;

      case RenderCommandType.Rect:
        context.rect(
          view.getFloat64(offset, true),
          view.getFloat64(offset + 8, true),
          view.getFloat64(offset + 16, true),
          view.getFloat64(offset + 24, true),
        );
        offset += 32;
        break;

      case RenderCommandType.Arc:
        context.arc(
          view.getFloat64(offset, true),
          view.getFloat64(offset + 8, true),
          view.getFloat64(offset + 16, true),
          view.getFloat64(offset + 24, true),
          view.getFloat64(offset + 32, true),
        );
        offset += 40;
        break;

      case RenderCommandType.SetStrokeStyle: {
        const r = view.getUint8(offset);
        const g = view.getUint8(offset + 1);
        const b = view.getUint8(offset + 2);
        const a = view.getUint8(offset + 3) / 255;
        context.strokeStyle = `rgba(${r},${g},${b},${a})`;
        offset += 4;
        break;
      }

      case RenderCommandType.SetFillStyle: {
        const r = view.getUint8(offset);
        const g = view.getUint8(offset + 1);
        const b = view.getUint8(offset + 2);
        const a = view.getUint8(offset + 3) / 255;
        context.fillStyle = `rgba(${r},${g},${b},${a})`;
        offset += 4;
        break;
      }

      case RenderCommandType.SetLineWidth:
        context.lineWidth = view.getFloat64(offset, true);
        offset += 8;
        break;

      case RenderCommandType.SetTransform:
        context.setTransform(
          view.getFloat64(offset, true),
          view.getFloat64(offset + 8, true),
          view.getFloat64(offset + 16, true),
          view.getFloat64(offset + 24, true),
          view.getFloat64(offset + 32, true),
          view.getFloat64(offset + 40, true),
        );
        offset += 48;
        break;

      default:
        // Unknown command — skip. Cannot continue safely since sizes are variable.
        return;
    }
  }
}
